import React, { useEffect, useState } from "react";
import { getFreelancerDashboard } from "../../api/api";
import { useNavigate } from "react-router-dom";

const fmt = (d) => d ? new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" }) : "";

export default function FreelancerDashboard() {
  const user = JSON.parse(localStorage.getItem("user") || "{}");
  const navigate = useNavigate();
  const [data, setData] = useState({ activeProjects: 0, pendingProposals: 0, projects: [] });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getFreelancerDashboard()
      .then(r => { setData(r.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return (
    <div style={{ background:"#f8fafc", minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center" }}>
      <div style={{ color:"#0f766e", fontSize:"16px", fontWeight:"600" }}>Loading...</div>
    </div>
  );

  const accepted = data.projects?.filter(p => p.proposal_status === "accepted").length || 0;

  const statCards = [
    { label: "Applied Projects", value: data.activeProjects, color: "#0f766e", bg: "#f0fdf9", border: "#99f6e4", icon: "📁", sub: "Total applied" },
    { label: "Total Proposals", value: data.pendingProposals, color: "#7c3aed", bg: "#faf5ff", border: "#ddd6fe", icon: "📄", sub: "Submitted" },
    { label: "Accepted", value: accepted, color: "#16a34a", bg: "#f0fdf4", border: "#bbf7d0", icon: "✅", sub: "Projects won" },
    { label: "Account Type", value: "Freelancer", color: "#0891b2", bg: "#f0f9ff", border: "#bae6fd", icon: "👤", sub: user.email?.slice(0, 22) },
  ];

  const statusStyle = (s) => {
    const m = {
      accepted: { bg:"#dcfce7", color:"#15803d", border:"#86efac" },
      rejected: { bg:"#fee2e2", color:"#dc2626", border:"#fca5a5" },
      pending:  { bg:"#fef9c3", color:"#a16207", border:"#fde047" },
    };
    return m[s] || m.pending;
  };

  return (
    <div style={{ background:"#f8fafc", minHeight:"100vh", padding:"32px", fontFamily:"'Segoe UI', sans-serif" }}>

      {/* HEADER */}
      <div style={{ marginBottom:"28px" }}>
        <h1 style={{ fontSize:"26px", fontWeight:"700", color:"#0f172a", margin:0 }}>
          Welcome back, {user.name} 👋
        </h1>
        <p style={{ color:"#64748b", fontSize:"14px", marginTop:"4px" }}>Here's your freelancing overview</p>
      </div>

      {/* STAT CARDS */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:"16px", marginBottom:"28px" }}>
        {statCards.map((c, i) => (
          <div key={i} style={{ background:"white", border:`1px solid ${c.border}`, borderTop:`3px solid ${c.color}`, borderRadius:"12px", padding:"20px", boxShadow:"0 1px 4px rgba(0,0,0,0.05)" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:"10px" }}>
              <span style={{ fontSize:"11px", fontWeight:"700", color:"#94a3b8", textTransform:"uppercase", letterSpacing:"0.8px" }}>{c.label}</span>
              <span style={{ fontSize:"18px" }}>{c.icon}</span>
            </div>
            <p style={{ fontSize:"28px", fontWeight:"800", color:c.color, margin:"0 0 4px" }}>{c.value}</p>
            <p style={{ fontSize:"11px", color:"#94a3b8", margin:0 }}>{c.sub}</p>
          </div>
        ))}
      </div>

      {/* PROJECTS TABLE */}
      <div style={{ background:"white", border:"1px solid #e2e8f0", borderRadius:"14px", overflow:"hidden", boxShadow:"0 1px 4px rgba(0,0,0,0.04)" }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"18px 22px", borderBottom:"1px solid #f1f5f9" }}>
          <h2 style={{ fontSize:"15px", fontWeight:"700", color:"#0f172a", margin:0 }}>Projects You Applied To</h2>
          <button onClick={() => navigate("/freelancer/find-projects")}
            style={{ fontSize:"12px", fontWeight:"600", color:"#0f766e", background:"#f0fdf9", border:"1px solid #99f6e4", borderRadius:"8px", padding:"6px 14px", cursor:"pointer" }}>
            Browse Projects →
          </button>
        </div>

        {(!data.projects || data.projects.length === 0) ? (
          <div style={{ textAlign:"center", padding:"48px", color:"#94a3b8" }}>
            <div style={{ fontSize:"36px", marginBottom:"8px" }}>🔍</div>
            <p>No projects yet. Start browsing!</p>
          </div>
        ) : data.projects.map((p) => (
          <div key={p.id} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"16px 22px", borderBottom:"1px solid #f8fafc", transition:"background 0.15s" }}>
            <div>
              <p style={{ fontSize:"14px", fontWeight:"600", color:"#0f172a", margin:"0 0 3px" }}>{p.title}</p>
              <p style={{ fontSize:"12px", color:"#94a3b8", margin:0 }}>
                {p.description?.slice(0, 70)}... · Budget: ₹{p.budget}
                {p.my_bid ? ` · Your Bid: ₹${p.my_bid}` : ""}
                {p.deadline ? ` · 📅 ${fmt(p.deadline)}` : ""}
              </p>
            </div>
            {p.proposal_status && (() => {
              const s = statusStyle(p.proposal_status);
              return (
                <span style={{ background:s.bg, color:s.color, border:`1px solid ${s.border}`, fontSize:"11px", fontWeight:"700", padding:"4px 12px", borderRadius:"20px", textTransform:"capitalize", flexShrink:0 }}>
                  {p.proposal_status}
                </span>
              );
            })()}
          </div>
        ))}
      </div>
    </div>
  );
}
